use crate::bridge::extern_c_api as extern_api;
use data::*;

use proptest::prelude::*;

/// container for component's incoming port values
pub struct PreStateContainer {
  pub api_fanCmd: Option<TempControl_SysVerif::FanCmd>
}

/// setter for component's incoming port values
pub fn put_concrete_inputs_container(container: PreStateContainer)
{
  put_fanCmd(container.api_fanCmd);
}

/// setter for component's incoming port values
pub fn put_concrete_inputs(fanCmd: Option<TempControl_SysVerif::FanCmd>)
{
  put_fanCmd(fanCmd);
}

/// setter for IN EventDataPort
pub fn put_fanCmd(value: Option<TempControl_SysVerif::FanCmd>)
{
  *extern_api::IN_fanCmd.lock().unwrap_or_else(|e| e.into_inner()) = value
}

/// getter for OUT EventDataPort
pub fn get_fanAck() -> Option<TempControl_SysVerif::FanAck>
{
  return extern_api::OUT_fanAck.lock().unwrap_or_else(|e| e.into_inner()).clone()
}
